INSERT INTO `Quiz` (`question_id`, `question`, `correct_answer`, `answer_1`, `answer_2`, `answer_3`, `answer_4`) VALUES
(1, 'Какое существо считается покровителем водоемов и известно своей игривостью?', 'Каппа', 'Каппа', 'Бакэмоно', 'Нэкокуби', 'Тануки'),
(2, 'Какой мифический зверь имеет девять хвостов?', 'Кицунэ', 'Инугами', 'Кицунэ', 'Оками', 'Райдзю'),
(3, 'Существо в японской мифологии известно как «демон» и часто изображается с рогами и острыми зубами?', 'Они', 'Кирин', 'Они', 'Фатакучи-онна', 'Му-онна'),
(4, 'Какой дух в японской мифологии считается покровителем грозы и молний?', 'Райдзю', 'Умибодзу', 'Кицунэ', 'Сагари', 'Райдзю'),
(5, 'Какое существо в японской мифологии является духом старых предметов, которые приобрели сознание?', 'Цукумогами', 'Тануки', 'Инугами', 'Цукумогами', 'Шиши'),
(6, 'Какое существо известно своей способностью вызывать шторма и считается духом моря?', 'Умибодзу', 'Умибодзу', 'Каппа', 'Ибису', 'Они'),
(7, 'Когда японский крестьянин ложится спать или просыпается, он вспоминает Баку. Кем он был? ', 'Пожиратель кошмарных снов', 'Предсказатель будущего', 'Проводник в мир духов ', 'Пожиратель кошмарных снов', 'Защитник от злых духов'),
(8, 'Дух, потерявший свое дитя во время войны?', 'Му-онна', 'Ао-адон', 'Му-онна', 'Гаки', 'Аканамэ'),
(9, 'Верхняя часть этого духа имеет голову жнгщины, но туловище имеет вид змеиного тела', 'Нурэ-онна', 'Тануки', 'Аканамэ', 'Рокурокуби', 'Нурэ-онна'),
(10, 'Дух, умеющий отрывать голову от своего тела', 'Нэкокуби', 'Сагари', 'Нэкокуби', 'Рокурокуби', 'Оками'),
(11, 'Голова лошади, свисающая с ветки дерева.', 'Сагари', 'Сагари', 'Оками', 'Аканамэ', 'Шиши'),
(12, 'Дух, имеющий способность удлинять свою шею.', 'Рокурокуби', 'Ао-адон', 'Рокурокуби', 'Фатакучи-онна', 'Йорогумо');
